import { successResponse, outputAndExit } from '@/cli/output';

import { getSettings, setSettings } from '@/shared/settings';
import { DEFAULT_MAX_AMOUNT } from '@/operations/fetch/types';

import type { Command } from '@/types';

const VALID_KEYS = ['maxAmount'] as const;

export const settingsGetCommand: Command = args => {
  const settings = getSettings();

  outputAndExit(successResponse(settings), args);
};

export const settingsSetCommand: Command<{
  key: string;
  value: string;
}> = args => {
  const { key, value } = args;

  if (!VALID_KEYS.includes(key as (typeof VALID_KEYS)[number])) {
    console.error(
      `Unknown setting: ${key}. Valid settings: ${VALID_KEYS.join(', ')}`
    );
    process.exit(1);
  }

  if (key === 'maxAmount') {
    const num = Number(value);
    if (isNaN(num) || num <= 0) {
      console.error('maxAmount must be a positive number');
      process.exit(1);
    }
    setSettings({ maxAmount: num });
  }

  const settings = getSettings();

  outputAndExit(
    successResponse({
      maxAmount: settings.maxAmount ?? DEFAULT_MAX_AMOUNT,
    }),
    args
  );
};
